import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Box,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  IconButton,
  Stack,
  CircularProgress,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import EditIcon from '@mui/icons-material/Edit';
import DeleteIcon from '@mui/icons-material/Delete';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';

const API_URL = 'http://localhost:3000/api/products'; // আপনার ব্যাকএন্ড ইউআরএল দিন

export default function HQDashboard() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [open, setOpen] = useState(false);
  const [selectedImages, setSelectedImages] = useState([]);
  const [form, setForm] = useState({ name: '', details: '', price: '' });

  // ১. সব প্রোডাক্ট লোড করা (GET /api/products)
  const fetchProducts = async () => {
    try {
      setLoading(true);
      const response = await axios.get(API_URL);
      setProducts(response.data.data || response.data); // API স্ট্রাকচার অনুযায়ী অ্যাডজাস্ট করুন
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  // ২. ইমেজ হ্যান্ডেল করা
  const handleImageChange = (e) => {
    setSelectedImages(e.target.files);
  };

  // ৩. নতুন প্রোডাক্ট তৈরি করা (POST /api/products)
  const handleSubmit = async (e) => {
    e.preventDefault();

    // ইমেজ পাঠানোর জন্য FormData ব্যবহার করতে হবে
    const formData = new FormData();
    formData.append('name', form.name);
    formData.append('details', form.details);
    formData.append('base_price', form.price);

    // একাধিক ইমেজ লুপ করে অ্যাপেন্ড করা
    for (let i = 0; i < selectedImages.length; i++) {
      formData.append('images', selectedImages[i]);
    }

    try {
      await axios.post(API_URL, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      alert('Product Created Successfully!');
      handleClose();
      fetchProducts(); // লিস্ট আপডেট করা
    } catch (error) {
      console.error('Error creating product:', error);
      alert('Failed to create product');
    }
  };

  // ৪. প্রোডাক্ট ডিলিট করা (DELETE /api/products/:id)
  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`${API_URL}/${id}`);
        fetchProducts();
      } catch (error) {
        console.error('Error deleting product:', error);
      }
    }
  };

  const handleOpen = () => setOpen(true);
  const handleClose = () => {
    setOpen(false);
    setForm({ name: '', details: '', price: '' });
    setSelectedImages([]);
  };

  return (
    <Box sx={{ padding: '24px' }}>
      <Stack
        direction="row"
        justifyContent="space-between"
        alignItems="center"
        sx={{ marginBottom: '24px' }}
      >
        <Typography variant="h4" sx={{ fontWeight: 'bold' }}>
          Master Menu
        </Typography>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={handleOpen}
        >
          Add New Product
        </Button>
      </Stack>

      <Card variant="outlined">
        <CardContent>
          {loading ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
              <CircularProgress />
            </Box>
          ) : (
            <Table>
              <TableHead sx={{ backgroundColor: '#f5f5f5' }}>
                <TableRow>
                  <TableCell>Image</TableCell>
                  <TableCell>Name</TableCell>
                  <TableCell>Price</TableCell>
                  <TableCell align="right">Actions</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {products.map((p) => (
                  <TableRow key={p.id}>
                    <TableCell>
                      <img
                        src={p.images?.[0]?.url || 'https://placeholder.com'}
                        alt={p.name}
                        style={{
                          width: 50,
                          height: 50,
                          borderRadius: 8,
                          objectFit: 'cover',
                        }}
                      />
                    </TableCell>
                    <TableCell sx={{ fontWeight: 'bold' }}>{p.name}</TableCell>
                    <TableCell>৳{p.base_price}</TableCell>
                    <TableCell align="right">
                      <IconButton color="primary">
                        <EditIcon />
                      </IconButton>
                      <IconButton
                        color="error"
                        onClick={() => handleDelete(p.id)}
                      >
                        <DeleteIcon />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Create Dialog */}
      <Dialog open={open} onClose={handleClose} fullWidth maxWidth="sm">
        <DialogTitle sx={{ fontWeight: 'bold' }}>
          Add Master Menu Item
        </DialogTitle>
        <form onSubmit={handleSubmit}>
          <DialogContent>
            <Stack spacing={2}>
              <TextField
                label="Product Name"
                fullWidth
                required
                onChange={(e) => setForm({ ...form, name: e.target.value })}
              />
              <TextField
                label="Details"
                fullWidth
                multiline
                rows={2}
                onChange={(e) => setForm({ ...form, details: e.target.value })}
              />
              <TextField
                label="Base Price"
                type="number"
                fullWidth
                required
                onChange={(e) => setForm({ ...form, price: e.target.value })}
              />
              <Button
                variant="outlined"
                component="label"
                startIcon={<CloudUploadIcon />}
              >
                {selectedImages.length > 0
                  ? `${selectedImages.length} Images Selected`
                  : 'Upload Images'}
                <input
                  type="file"
                  hidden
                  multiple
                  accept="image/*"
                  onChange={handleImageChange}
                />
              </Button>
            </Stack>
          </DialogContent>
          <DialogActions sx={{ p: 3 }}>
            <Button onClick={handleClose}>Cancel</Button>
            <Button type="submit" variant="contained">
              Save Product
            </Button>
          </DialogActions>
        </form>
      </Dialog>
    </Box>
  );
}
